class Solution {
public:
    int removeDuplicates(vector<int>& nums) {
      int n= nums.size();
      int s= 0;
      for(int i=1;i<n;i++){
        if(nums[s]!= nums[i]){
          s++;
          nums[s]= nums[i];
        }

      }
      return s+1;
    }
};

