class Solution {
public:
    int maxProfit(vector<int>& prices) {
      int n= prices.size();
      int start= prices[0];
      int profit= 0;
      for(int i=1;i<n;i++){
        int currProfit=  prices[i]- start;
        profit= max(profit,currProfit);
        start= min(start,prices[i]);
      }
      return profit;
    }
};

class Solution {
public:
    vector<int> spiralOrder(vector<vector<int>>& matrix) {
        int m = matrix.size();
        int n = matrix[0].size();

        int top = 0;
        int bottom = m - 1;
        int l = 0;
        int r = n - 1;

        vector<int> ans;

        while (top <= bottom && l <= r) {

            // Top row
            for (int i = l; i <= r; i++) {
                ans.push_back(matrix[top][i]);
            }
            top++;

            // Right column
            for (int i = top; i <= bottom; i++) {
                ans.push_back(matrix[i][r]);
            }
            r--;

            // Bottom row
            if (top <= bottom) {
                for (int i = r; i >= l; i--) {
                    ans.push_back(matrix[bottom][i]);
                }
                bottom--;
            }

            // Left column
            if (l <= r) {
                for (int i = bottom; i >= top; i--) {
                    ans.push_back(matrix[i][l]);
                }
                l++;
            }
        }

        return ans;
    }
};

