class Solution {
public:
    string longestCommonPrefix(vector<string>& strs) {
        sort(strs.begin(),strs.end());
        int n= strs.size();
        string s= strs[0];
        string m= strs[n-1];
        string ans= "";
        for(int i=0;i< min(s.length(),m.length());i++){
          if(s[i] !=m[i]){
            return ans;
          }
          ans+= s[i];
        }
        return ans;
    }
